//! XJC-OS 宏内核核心模块
//!
//! 基于 ArceOS 组件框架实现的宏内核，支持加载和运行用户态程序。
//! 实现 Linux 兼容系统调用接口，可运行 LTP、lmbench、cyclictest 等
//! 标准 Linux 测试套件。
//!
//! 模块架构：
//!   - entry:    内核入口点，负责 init 进程的创建和启动
//!   - config:   多架构配置（RISC-V / LoongArch / x86_64 / AArch64）
//!   - syscall:  系统调用实现（进程、内存、文件系统、网络等）
//!   - mm:       内存管理（地址空间、页表、mmap 等）
//!   - file:     文件描述符表、管道、epoll、eventfd、signalfd 等
//!   - task:     任务管理（线程、进程、信号）
//!   - pseudofs: 伪文件系统（/proc, /dev, /tmp, /sys 等）
//!   - time:     时间管理（高精度定时器、alarm）

#![no_std]
#![feature(likely_unlikely)]
#![feature(bstr)]
#![allow(missing_docs)]
#![allow(dead_code)]
#![allow(clippy::not_unsafe_ptr_arg_deref)]

extern crate alloc;
extern crate axruntime;

#[macro_use]
extern crate axlog;

pub mod entry;

mod config;
mod file;
mod mm;
mod pseudofs;
mod syscall;
mod task;
mod time;

//! 内核入口点 —— init 进程生命周期管理。
//!
//! 本模块负责创建 PID 1（init 进程）并管理其完整生命周期：
//!   1. 挂载伪文件系统（/proc, /dev, /tmp 等）
//!   2. 解析 init 进程的参数和可执行文件路径
//!   3. 创建用户地址空间并加载 init 程序（/src/init.sh 的内容）
//!   4. 等待 init 进程退出
//!   5. 执行关机清理：先 SIGTERM，再 SIGKILL 残留用户进程
//!   6. 卸载所有文件系统并刷写根文件系统
//!   7. 调用系统关机

use alloc::{
    collections::btree_set::BTreeSet,
    string::{String, ToString},
    sync::Arc,
    vec,
    vec::Vec,
};
use core::time::Duration;

use axfs::FS_CONTEXT;
use axhal::uspace::UserContext;
use axsync::Mutex;
use axtask::{AxTaskExt, AxTaskRef, TaskState, sleep, spawn_task};
use starry_process::{Pid, Process};
use starry_signal::{SignalInfo, Signo};

use crate::{
    file::FD_TABLE,
    mm::{copy_from_kernel, load_user_app, new_user_aspace_empty},
    pseudofs::{self, dev::tty::N_TTY},
    task::{
        AsThread, ProcessData, Thread, add_task_to_table, cleanup_task_tables, new_user_task,
        send_signal_to_process, spawn_alarm_task, tasks,
    },
};

const TEST_RUNNER_ENTRY: &str = "@xjc-test-runner";
const TEST_RUNNER_CANDIDATES: &[&str] = &[
    "/busybox",
    "/bin/busybox",
    "/musl/busybox",
    "/glibc/busybox",
    "/bin/sh",
];
const SHUTDOWN_POLL_INTERVAL: Duration = Duration::from_millis(50);
const SHUTDOWN_TERM_ROUNDS: usize = 20;
const SHUTDOWN_KILL_ROUNDS: usize = 20;

/// 解析 init 进程的启动参数。
///
/// 如果 args[0] 是特殊的测试运行器标记（`@xjc-test-runner`），
/// 则 args[1] 是一个内嵌的 shell 脚本内容。此函数将其拼接为
/// `/bin/busybox sh -c "<脚本内容>"` 的形式，供 exec 使用。
fn resolve_init_args(args: &[String]) -> Vec<String> {
    if args.first().map(String::as_str) != Some(TEST_RUNNER_ENTRY) {
        return args.to_vec();
    }

    let script = args.get(1).cloned().unwrap_or_default();
    let fs = FS_CONTEXT.lock();
    let runner = TEST_RUNNER_CANDIDATES
        .iter()
        .copied()
        .find(|path| fs.resolve(path).is_ok())
        .unwrap_or("/bin/sh");
    drop(fs);

    let mut resolved = if runner.ends_with("/sh") {
        vec![runner.to_string(), "-c".to_string(), script]
    } else {
        vec![
            runner.to_string(),
            "sh".to_string(),
            "-c".to_string(),
            script,
        ]
    };
    resolved.extend(args.iter().skip(2).cloned());
    resolved
}

fn lingering_user_tasks(init_tid: Pid) -> Vec<AxTaskRef> {
    tasks()
        .into_iter()
        .filter(|task| {
            let tid = task.id().as_u64() as Pid;
            tid != init_tid && task.state() != TaskState::Exited
        })
        .collect()
}

fn lingering_process_ids(tasks: &[AxTaskRef]) -> Vec<Pid> {
    let mut pids = BTreeSet::new();
    for task in tasks {
        pids.insert(task.as_thread().proc_data.proc.pid());
    }
    pids.into_iter().collect()
}

fn wait_for_lingering_user_tasks(init_tid: Pid, rounds: usize) -> Vec<AxTaskRef> {
    let mut pending = lingering_user_tasks(init_tid);
    for _ in 0..rounds {
        if pending.is_empty() {
            break;
        }
        sleep(SHUTDOWN_POLL_INTERVAL);
        cleanup_task_tables();
        pending = lingering_user_tasks(init_tid);
    }
    pending
}

/// 关机前清理残留用户进程的渐进式策略：
///
/// 1. 先发送 SIGTERM（给进程优雅退出的机会）
/// 2. 等待 SHUTDOWN_TERM_ROUNDS 轮后，仍未退出的进程发送 SIGKILL
/// 3. 最终如果仍有残留，记录警告但继续关机流程
///
/// 不直接读 /proc/PID/stat 来判断进程状态，因为处于 D 状态
/// （不可中断睡眠）的进程会导致读取阻塞。
fn drain_lingering_user_tasks(init_tid: Pid) {
    let mut pending = lingering_user_tasks(init_tid);
    if pending.is_empty() {
        return;
    }

    let mut pids = lingering_process_ids(&pending);
    warn!(
        "Init exited with lingering user processes {:?}; sending SIGTERM before shutdown",
        pids
    );
    for pid in &pids {
        let _ = send_signal_to_process(*pid, Some(SignalInfo::new_kernel(Signo::SIGTERM)));
    }

    pending = wait_for_lingering_user_tasks(init_tid, SHUTDOWN_TERM_ROUNDS);
    if pending.is_empty() {
        return;
    }

    pids = lingering_process_ids(&pending);
    warn!(
        "User processes {:?} ignored SIGTERM; escalating to SIGKILL",
        pids
    );
    for pid in &pids {
        let _ = send_signal_to_process(*pid, Some(SignalInfo::new_kernel(Signo::SIGKILL)));
    }

    pending = wait_for_lingering_user_tasks(init_tid, SHUTDOWN_KILL_ROUNDS);
    if pending.is_empty() {
        return;
    }

    let tids = pending
        .iter()
        .map(|task| task.id().as_u64() as Pid)
        .collect::<Vec<_>>();
    warn!(
        "Proceeding with shutdown while user tasks {:?} are still alive",
        tids
    );
}

/// Initialize and run initproc.
pub fn init(args: &[String], envs: &[String], init_files: &[(&str, &[u8])]) {
    warn!("XJC init: kernel entry start");
    let _ = axhal::irq::register(axhal::irq::IPI_IRQ, || {});
    pseudofs::mount_all().expect("Failed to mount pseudofs");
    spawn_alarm_task();
    warn!("XJC init: pseudofs mounted and alarm task started");

    // 大文件不放进 shell argv，避免触发单参数长度限制和启动阶段额外内存峰值。
    for &(path, contents) in init_files {
        let file = {
            let fs = FS_CONTEXT.lock();
            axfs::File::create(&fs, path)
                .unwrap_or_else(|err| panic!("Failed to create init file {path}: {err:?}"))
        };
        let written = file
            .write(contents)
            .unwrap_or_else(|err| panic!("Failed to write init file {path}: {err:?}"));
        assert_eq!(written, contents.len(), "Short write for init file {path}");
    }

    let args = resolve_init_args(args);
    warn!("XJC init: resolved init argv[0]={}", args[0]);
    let loc = FS_CONTEXT
        .lock()
        .resolve(&args[0])
        .expect("Failed to resolve executable path");
    let path = loc
        .absolute_path()
        .expect("Failed to get executable absolute path");
    let name = loc.name();

    let mut uspace = new_user_aspace_empty()
        .and_then(|mut it| {
            copy_from_kernel(&mut it)?;
            Ok(it)
        })
        .expect("Failed to create user address space");
    warn!("XJC init: user address space prepared");

    let (entry_vaddr, ustack_top) = load_user_app(&mut uspace, None, &args, envs)
        .unwrap_or_else(|e| panic!("Failed to load user app: {}", e));
    warn!("XJC init: user app loaded");

    let uctx = UserContext::new(entry_vaddr.into(), ustack_top, 0);
    let mut task = new_user_task(name, uctx, 0);
    task.ctx_mut().set_page_table_root(uspace.page_table_root());

    let pid = task.id().as_u64() as Pid;
    let proc = Process::new_init(pid);
    proc.add_thread(pid);

    N_TTY.bind_to(&proc).expect("Failed to bind ntty");

    let proc = ProcessData::new(
        proc,
        path.to_string(),
        Arc::new(args.to_vec()),
        Arc::new(Mutex::new(uspace)),
        Arc::default(),
        None,
    );

    {
        let mut scope = proc.scope.write();
        crate::file::add_stdio(&mut FD_TABLE.scope_mut(&mut scope).write())
            .expect("Failed to add stdio");
    }

    let thr = Thread::new(pid, proc);
    *task.task_ext_mut() = Some(AxTaskExt::from_impl(thr));

    let task = spawn_task(task);
    add_task_to_table(&task);
    warn!("XJC init: init task spawned pid={pid}");

    let exit_code = task.join();
    info!("Init process exited with code: {exit_code:?}");
    cleanup_task_tables();
    drain_lingering_user_tasks(pid);
    cleanup_task_tables();

    let cx = FS_CONTEXT.lock();
    cx.root_dir()
        .unmount_all()
        .expect("Failed to unmount all filesystems");
    cx.root_dir()
        .filesystem()
        .flush()
        .expect("Failed to flush rootfs");
    drop(cx);

    warn!("XJC init: userspace finished, powering off");
    axhal::power::system_off();
}

#![no_std]
#![no_main]

extern crate alloc;

use alloc::{string::String, vec, vec::Vec};

const TEST_RUNNER_ENTRY: &str = "@xjc-test-runner";

fn get_boot_arg(name: &str) -> Option<&'static str> {
    if let Some(bootargs) = axhal::dtb::get_chosen_bootargs() {
        for part in bootargs.split_ascii_whitespace() {
            if let Some((key, val)) = part.split_once('=') {
                if key == name {
                    return Some(val);
                }
            }
        }
    }
    None
}

fn get_test_group() -> &'static str {
    if let Some(group) = get_boot_arg("TEST_GROUP") {
        return group;
    }
    if let Some(group) = option_env!("XJC_TEST_GROUP") {
        return group;
    }
    if cfg!(target_arch = "loongarch64") {
        "basic"
    } else {
        "all"
    }
}

fn get_arch_name() -> &'static str {
    if cfg!(target_arch = "loongarch64") {
        "loongarch64"
    } else if cfg!(target_arch = "riscv64") {
        "riscv64"
    } else {
        "unknown"
    }
}

/// Encode binary data as octal escape sequences for busybox printf.
/// We use `\\NNN` (double backslash) because the shell's double-quote
/// expansion strips one layer of backslashes before printf sees the string.
/// Split into 30KB chunks to stay under Linux MAX_ARG_STRLEN (128KB).
fn encode_octal_chunked(data: &[u8]) -> Vec<(String, String)> {
    const CHUNK: usize = 30000;
    let mut result = Vec::new();
    let mut offset = 0;
    let mut idx = 0;
    while offset < data.len() {
        let end = (offset + CHUNK).min(data.len());
        let chunk = &data[offset..end];
        let mut out = String::with_capacity(chunk.len() * 5);
        for &b in chunk {
            use core::fmt::Write;
            // Double backslash: shell strips one, printf sees one
            let _ = write!(out, "\\\\{:03o}", b);
        }
        let name = if idx == 0 {
            alloc::format!("LTP_RUNNER_OCTAL")
        } else {
            alloc::format!("LTP_RUNNER_OCTAL_{}", idx)
        };
        result.push((name, out));
        offset = end;
        idx += 1;
    }
    result
}

pub fn build_cmdline() -> Vec<String> {
    let test_group = get_test_group();
    let arch_name = get_arch_name();
    let init_sh = include_str!("init.sh");
    let ltp_wl_common = include_str!("ltp_whitelist_common.txt");
    let mut cmd = alloc::format!("TEST_GROUP={test_group}\nXJC_ARCH={arch_name}\n");
    for (env_name, compile_value) in [
        ("LTP_CASES", option_env!("XJC_LTP_CASES")),
        ("LTP_PREFIXES", option_env!("XJC_LTP_PREFIXES")),
        ("LTP_CASE_TIMEOUT", option_env!("XJC_LTP_CASE_TIMEOUT")),
        (
            "LTP_CONTROLLER_TIMEOUT",
            option_env!("XJC_LTP_CONTROLLER_TIMEOUT"),
        ),
        (
            "LTP_CLOSE_RANGE_TIMEOUT",
            option_env!("XJC_LTP_CLOSE_RANGE_TIMEOUT"),
        ),
        (
            "LTP_FS_PERMS_TIMEOUT",
            option_env!("XJC_LTP_FS_PERMS_TIMEOUT"),
        ),
        (
            "LTP_MALLOCSTRESS_TIMEOUT",
            option_env!("XJC_LTP_MALLOCSTRESS_TIMEOUT"),
        ),
        ("LTP_RUN_SLOW", option_env!("XJC_LTP_RUN_SLOW")),
        ("LTP_OUTPUT", option_env!("XJC_LTP_OUTPUT")),
        ("LTP_DEBUG", option_env!("XJC_LTP_DEBUG")),
    ] {
        let value = get_boot_arg(env_name).or(compile_value);
        if let Some(value) = value.filter(|value| !value.is_empty()) {
            cmd.push_str(env_name);
            cmd.push('=');
            cmd.push_str(value);
            cmd.push('\n');
        }
    }
    // NOTE: export is required because the C runner (exec'd as a separate
    // process) reads these variables via getenv(). Shell variables without
    // export are not inherited by child processes.
    cmd.push_str("export ");
    cmd.push_str(ltp_wl_common);
    cmd.push('\n');

    // Embed compiled LTP runner binary (octal-encoded in chunks)
    let ltp_runner_bin: &[u8] = if cfg!(target_arch = "loongarch64") {
        include_bytes!("../tools/ltp-runner-loongarch64")
    } else {
        include_bytes!("../tools/ltp-runner-riscv64")
    };
    for (name, encoded) in encode_octal_chunked(ltp_runner_bin) {
        cmd.push_str(&name);
        cmd.push('=');
        cmd.push_str(&encoded);
        cmd.push('\n');
    }

    cmd.push_str(init_sh);
    vec![String::from(TEST_RUNNER_ENTRY), cmd]
}

#[unsafe(no_mangle)]
fn main() {
    let args = build_cmdline();
    let envs = [];
    #[cfg(target_arch = "loongarch64")]
    let init_files: &[(&str, &[u8])] = &[(
        "/tmp/cyclictest-loongarch64-musl.gz",
        include_bytes!("../tools/cyclictest-loongarch64-musl.gz"),
    )];
    #[cfg(not(target_arch = "loongarch64"))]
    let init_files: &[(&str, &[u8])] = &[];
    xjc_kernel::entry::init(&args, &envs, init_files);
}

//! 系统调用分发层 —— Linux 系统调用号到内核实现的映射。
//!
//! # 架构
//!
//! 本模块是 XJC-OS 内核中所有 Linux 系统调用的统一入口点。
//! `handle_syscall()` 从用户上下文 `UserContext` 中提取系统调用号（sysno），
//! 通过一个巨大的 `match` 语句将其路由到对应的处理函数，最后将返回值
//! 写回 `UserContext` 的 retval 寄存器。
//!
//! # 分类
//!
//! 系统调用按功能分为以下子模块：
//!
//! | 子模块   | 涵盖的 Linux 系统调用                               |
//! |----------|-----------------------------------------------------|
//! | `fs`     | 文件系统控制（ioctl, chdir, mkdirat, getdents64 等）  |
//! | `task`   | 进程/线程管理（clone, execve, wait4, exit 等）        |
//! | `mm`     | 内存管理（mmap, munmap, brk, mprotect 等）           |
//! | `signal` | 信号处理（rt_sigaction, kill, futex 等）             |
//! | `net`    | 网络套接字（socket, bind, sendto, recvfrom 等）       |
//! | `io_mpx` | I/O 多路复用（select, poll, epoll）                  |
//! | `ipc`    | System V IPC（shm, sem, msg）                       |
//! | `sync`   | 同步原语（membarrier）                               |
//! | `time`   | 时间查询（gettimeofday, clock_gettime 等）           |
//! | `timer`  | POSIX 定时器 + timerfd                               |
//! | `sys`    | 系统信息（uname, sysinfo, getuid 等）                |
//! | `resources` | 资源限制（rlimit）                                   |
//!
//! # 错误处理约定
//!
//! 所有 sys_* 函数返回 `AxResult<isize>`：
//! - `Ok(n)` → 成功，返回值 `n` 写入用户 retval
//! - `Err(e)` → 失败，`-LinuxError::from(e).code()` 写入用户 retval
//!
//! # 架构差异
//!
//! 不同架构（x86_64, RISC-V, LoongArch, AArch64）的系统调用号不同。
//! 通过 `#[cfg(target_arch = "...")]` 条件编译处理差异。
//! 例如 `stat` 在 x86_64 上是独立的系统调用，而在 RISC-V/LoongArch
//! 上合并为 `fstatat`（通过 AT_EMPTY_PATH 标志模拟）。
//!
//! # 未实现的系统调用
//!
//! 部分系统调用返回 `dummy fd`（打开 /dev/null 或返回无害的 fd），
//! 让用户程序在不支持的接口上也能正常运行（而不是收到 ENOSYS 后崩溃）。
//! 其余的返回 `ENOSYS`（参数化）或 `EOPNOTSUPP`（xattr 类）。

mod fs;
mod io_mpx;
mod ipc;
mod mm;
mod net;
mod resources;
mod signal;
mod sync;
mod sys;
mod task;
mod time;
mod timer;

use axerrno::{AxError, LinuxError};
use axhal::uspace::UserContext;
use syscalls::Sysno;

pub use self::{
    fs::*, io_mpx::*, ipc::*, mm::*, net::*, resources::*, signal::*, sync::*, sys::*, task::*,
    time::*, timer::*,
};

/// 系统调用分发入口。
///
/// 从 `uctx` 中读取系统调用号，路由到对应的 sys_* 函数，
/// 并将返回值写入 `uctx.retval`。
///
/// 特殊处理的调用号：
/// - 无法解析的调用号 → 立即返回 `-ENOSYS`
/// - 调试模式下输出 `Syscall {name}` 跟踪日志
/// - 执行结束后输出 `Syscall {name} return {result}` 调试日志
pub fn handle_syscall(uctx: &mut UserContext) {
    let Some(sysno) = Sysno::new(uctx.sysno()) else {
        warn!("Invalid syscall number: {}", uctx.sysno());
        uctx.set_retval(-LinuxError::ENOSYS.code() as _);
        return;
    };

    trace!("Syscall {sysno:?}");

    let result = match sysno {
        // fs ctl
        Sysno::ioctl => sys_ioctl(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::chdir => sys_chdir(uctx.arg0() as _),
        Sysno::fchdir => sys_fchdir(uctx.arg0() as _),
        Sysno::chroot => sys_chroot(uctx.arg0() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::mkdir => sys_mkdir(uctx.arg0() as _, uctx.arg1() as _),
        Sysno::mkdirat => sys_mkdirat(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::getdents64 => sys_getdents64(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::link => sys_link(uctx.arg0() as _, uctx.arg1() as _),
        Sysno::linkat => sys_linkat(
            uctx.arg0() as _,
            uctx.arg1() as _,
            uctx.arg2() as _,
            uctx.arg3() as _,
            uctx.arg4() as _,
        ),
        #[cfg(target_arch = "x86_64")]
        Sysno::rmdir => sys_rmdir(uctx.arg0() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::unlink => sys_unlink(uctx.arg0() as _),
        Sysno::unlinkat => sys_unlinkat(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::getcwd => sys_getcwd(uctx.arg0() as _, uctx.arg1() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::symlink => sys_symlink(uctx.arg0() as _, uctx.arg1() as _),
        Sysno::symlinkat => sys_symlinkat(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::rename => sys_rename(uctx.arg0() as _, uctx.arg1() as _),
        #[cfg(not(target_arch = "riscv64"))]
        Sysno::renameat => sys_renameat(
            uctx.arg0() as _,
            uctx.arg1() as _,
            uctx.arg2() as _,
            uctx.arg3() as _,
        ),
        Sysno::renameat2 => sys_renameat2(
            uctx.arg0() as _,
            uctx.arg1() as _,
            uctx.arg2() as _,
            uctx.arg3() as _,
            uctx.arg4() as _,
        ),
        Sysno::sync => sys_sync(),
        Sysno::syncfs => sys_syncfs(uctx.arg0() as _),

        // file ops
        #[cfg(target_arch = "x86_64")]
        Sysno::chown => sys_chown(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        #[cfg(target_arch = "x86_64")]
        Sysno::lchown => sys_lchown(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::fchown => sys_fchown(uctx.arg0() as _, uctx.arg1() as _, uctx.arg2() as _),
        Sysno::fchownat => sys_fchownat(
            uctx.arg0() as _,
            uctx.arg1() as _,
            uctx.arg2() as _,
            uctx.arg3() as _,
            uctx.arg4() as _,
        ),
        #[cfg(target_arch = "x86_64")]
        Sysno::chmod => sys_chmod(uctx.arg0() as _, uctx.arg1() as _),
        Sysno::fchmod => sys_fchmod(uctx.arg0() as _, uctx.arg1() as _),
        Sysno::fchmodat | Sysno::fchmodat2 => sys_fchmodat(
            uctx.arg0() as _,
            uctx.arg1() as _,
