///  A wrapper type that assumes the inner type is `Sync`.
#[repr(transparent)]
pub struct AssumeSync<T>(pub T);

unsafe impl<T> Sync for AssumeSync<T> {}

impl<T> Deref for AssumeSync<T> {
    type Target = T;

    fn deref(&self) -> &Self::Target {
        &self.0
    }
}

/// The inner data of a thread.
pub struct Thread {
    /// The process data shared by all threads in the process.
    pub proc_data: Arc<ProcessData>,

    /// The clear thread tid field
    ///
    /// See <https://manpages.debian.org/unstable/manpages-dev/set_tid_address.2.en.html#clear_child_tid>
    ///
    /// When the thread exits, the kernel clears the word at this address if it
    /// is not NULL.
    clear_child_tid: AtomicUsize,

    /// The head of the robust list
    robust_list_head: AtomicUsize,

    /// Requested Linux scheduling policy for this thread.
    sched_policy: AtomicI32,

    /// Requested real-time scheduling priority for this thread.
    sched_priority: AtomicI32,

    /// The thread-level signal manager
    pub signal: Arc<ThreadSignalManager>,

    /// Time manager
    ///
    /// This is assumed to be `Sync` because it's only borrowed mutably during
    /// context switches, which is exclusive to the current thread.
    pub time: AssumeSync<RefCell<TimeManager>>,

    /// The OOM score adjustment value.
    oom_score_adj: AtomicI32,

    /// Ready to exit
    pub exit: Arc<AtomicBool>,

    /// Indicates whether the thread is currently accessing user memory.
    accessing_user_memory: AtomicBool,

    /// Skip one signal check after returning from a signal handler.
    block_next_signal_check: AtomicBool,

    /// 当前线程正在 rt_sigtimedwait 等待的信号集合。
    sigwait_set: SpinNoIrq<Option<SignalSet>>,

    /// Self exit event
    pub exit_event: Arc<PollSet>,

    /// Parent/child rendezvous for `CLONE_VFORK`.
    vfork_state: SpinNoIrq<Option<Arc<VforkState>>>,
}

pub struct VforkState {
    done: AtomicBool,
    wait_queue: WaitQueue,
}

impl VforkState {
    pub fn new() -> Arc<Self> {
        Arc::new(Self {
            done: AtomicBool::new(false),
            wait_queue: WaitQueue::new(),
        })
    }

    pub fn wait(&self) {
        self.wait_queue
            .wait_until(|| self.done.load(Ordering::Acquire));
    }

    pub fn complete(&self) {
        self.done.store(true, Ordering::Release);
        self.wait_queue.notify_all(false);
    }
}

impl Thread {
    /// Create a new [`Thread`].
    pub fn new(tid: u32, proc_data: Arc<ProcessData>) -> Box<Self> {
        Box::new(Thread {
            signal: ThreadSignalManager::new(tid, proc_data.signal.clone()),
            proc_data,
            clear_child_tid: AtomicUsize::new(0),
            robust_list_head: AtomicUsize::new(0),
            sched_policy: AtomicI32::new(0),
            sched_priority: AtomicI32::new(0),
            time: AssumeSync(RefCell::new(TimeManager::new())),
            exit: Arc::new(AtomicBool::new(false)),
            oom_score_adj: AtomicI32::new(200),
            accessing_user_memory: AtomicBool::new(false),
            block_next_signal_check: AtomicBool::new(false),
            sigwait_set: SpinNoIrq::new(None),
            exit_event: Arc::default(),
            vfork_state: SpinNoIrq::new(None),
        })
    }

    /// Get the clear child tid field.
    pub fn clear_child_tid(&self) -> usize {
        self.clear_child_tid.load(Ordering::Relaxed)
    }

    /// Set the clear child tid field.
    pub fn set_clear_child_tid(&self, clear_child_tid: usize) {
        self.clear_child_tid
            .store(clear_child_tid, Ordering::Relaxed);
    }

    /// Get the robust list head.
    pub fn robust_list_head(&self) -> usize {
        self.robust_list_head.load(Ordering::SeqCst)
    }

    /// Set the robust list head.
    pub fn set_robust_list_head(&self, robust_list_head: usize) {
        self.robust_list_head
            .store(robust_list_head, Ordering::SeqCst);
    }

    pub fn sched_policy(&self) -> i32 {
        self.sched_policy.load(Ordering::Acquire)
    }

    pub fn sched_priority(&self) -> i32 {
        self.sched_priority.load(Ordering::Acquire)
    }

    pub fn set_scheduler(&self, policy: i32, priority: i32) {
        self.sched_policy.store(policy, Ordering::Release);
        self.sched_priority.store(priority, Ordering::Release);
    }

    /// Get the oom score adjustment value.
    pub fn oom_score_adj(&self) -> i32 {
        self.oom_score_adj.load(Ordering::SeqCst)
    }

    /// Set the oom score adjustment value.
    pub fn set_oom_score_adj(&self, value: i32) {
        self.oom_score_adj.store(value, Ordering::SeqCst);
    }

    /// Check if the thread is ready to exit.
    pub fn pending_exit(&self) -> bool {
        self.exit.load(Ordering::Acquire)
    }

    /// Set the thread to exit.
    pub fn set_exit(&self) {
        self.exit.store(true, Ordering::Release);
    }

    pub fn block_next_signal_check(&self) {
        self.block_next_signal_check.store(true, Ordering::Release);
    }

    pub fn take_block_next_signal_check(&self) -> bool {
        self.block_next_signal_check.swap(false, Ordering::AcqRel)
    }

    pub fn set_sigwait_set(&self, set: Option<SignalSet>) {
        *self.sigwait_set.lock() = set;
    }

    pub fn waiting_for_signal(&self, signo: Signo) -> bool {
        self.sigwait_set
            .lock()
            .as_ref()
            .is_some_and(|set| set.has(signo))
    }

    /// Check if the thread is accessing user memory.
    pub fn is_accessing_user_memory(&self) -> bool {
        self.accessing_user_memory.load(Ordering::Acquire)
    }

    /// Set the accessing user memory flag.
    pub fn set_accessing_user_memory(&self, accessing: bool) {
        self.accessing_user_memory
            .store(accessing, Ordering::Release);
    }

    pub fn set_vfork_state(&self, state: Arc<VforkState>) {
        *self.vfork_state.lock() = Some(state);
    }

    pub fn complete_vfork(&self) {
        if let Some(state) = self.vfork_state.lock().take() {
            state.complete();
        }
    }
}

#[extern_trait]
impl TaskExt for Box<Thread> {
    fn on_enter(&self) {
        // The current task owns an Arc<ProcessData>, so the process scope lives
        // for the whole time this pointer is active on the CPU. Avoid taking
        // the scope RwLock on every context switch; the actual scoped objects
        // (FD table, FS context, etc.) have their own synchronization.
        let scope = unsafe { &*self.proc_data.scope.as_mut_ptr() };
        unsafe { ActiveScope::set(scope) };
    }

    fn on_leave(&self) {
        ActiveScope::set_global();
    }
}

