pub struct RobustListHead {
    pub list: RobustList,
    pub futex_offset: c_long,
    pub list_op_pending: *mut RobustList,
}

fn untag_robust_entry(entry: *mut RobustList) -> *mut RobustList {
    ((entry as usize) & !ROBUST_LIST_ENTRY_FLAGS) as *mut RobustList
}

fn handle_futex_death(entry: *mut RobustList, offset: i64) -> Option<()> {
    let address = (entry as u64)
        .checked_add_signed(offset)
        .and_then(|addr| usize::try_from(addr).ok())?;
    let key = FutexKey::new_current(address);

    let futex_table = futex_table_for(&key);

    let Some(futex) = futex_table.get(&key) else {
        return Some(());
    };
    futex.owner_dead.store(true, Ordering::SeqCst);
    futex.wq.wake(1, u32::MAX);
    Some(())
}

pub fn exit_robust_list(head: *const RobustListHead) {
    // Reference: https://elixir.bootlin.com/linux/v6.13.6/source/kernel/futex/core.c#L777
    // Linux treats robust-list cleanup as best-effort during exit: malformed
    // user pointers stop further scanning, but must not fail task teardown.

    let Ok(head_val) = head.vm_read() else {
        return;
    };
    let end_ptr = unsafe { &raw const (*head).list };
    let mut entry = untag_robust_entry(head_val.list.next);
    let offset = head_val.futex_offset;
    let pending = untag_robust_entry(head_val.list_op_pending);
    let mut limit = ROBUST_LIST_LIMIT;

    while !core::ptr::eq(entry, end_ptr) {
        let Ok(next_entry) = entry.vm_read().map(|node| untag_robust_entry(node.next)) else {
            break;
        };
        if entry != pending {
            let _ = handle_futex_death(entry, offset);
        }
        entry = next_entry;

        if limit == 0 {
            break;
        }
        limit -= 1;
        axtask::yield_now();
    }

    if !pending.is_null() {
        let _ = handle_futex_death(pending, offset);
    }
}

pub fn do_exit(exit_code: i32, group_exit: bool) {
    let curr = current();
    let thr = curr.as_thread();

    debug!("{} exit with code: {}", curr.id_name(), exit_code);
    thr.complete_vfork();

    let process = &thr.proc_data.proc;
    if group_exit && process.group_exit(exit_code) {
        let sig = SignalInfo::new_kernel(Signo::SIGKILL);
        for tid in process.threads() {
            if tid == curr.id().as_u64() as Pid {
                continue;
            }
            let _ = send_signal_to_thread(None, tid, Some(sig.clone()));
        }
    }

    let clear_child_tid = thr.clear_child_tid() as *mut u32;
    if !clear_child_tid.is_null() && clear_child_tid.vm_write(0).is_ok() {
        let key = FutexKey::new_current(clear_child_tid as usize);
        let table = futex_table_for(&key);
        let guard = table.get(&key);
        let mut woke = 0;
        if let Some(futex) = guard {
            woke = futex.wq.wake(1, u32::MAX);
        }
        if woke > 0 {
            axtask::yield_now();
        }
    }
    let head = thr.robust_list_head() as *const RobustListHead;
    if !head.is_null() {
        exit_robust_list(head);
    }

    if process.exit_thread(curr.id().as_u64() as Pid, exit_code) {
        close_all_file_like();
        clear_elf_cache();
        process.exit();
        if let Some(parent) = process.parent() {
            let exit_signal = thr.proc_data.exit_signal;

            if let Some(signo) = exit_signal {
                let _ = send_signal_to_process(parent.pid(), Some(SignalInfo::new_kernel(signo)));
            }
            if let Ok(data) = get_process_data(parent.pid()) {
                data.child_exit_event.wake();
            }
        }
        thr.proc_data.exit_event.wake();

        crate::syscall::SHM_MANAGER
            .lock()
            .clear_proc_shm(process.pid());
    }
    thr.set_exit();
    thr.exit_event.wake();
}

//! 任务信号处理 —— 信号发送、排队、递送和默认动作执行。
//!
//! 本模块是信号子系统的核心，负责：
//! - 将信号入队到目标进程/线程的 pending 队列
//! - 在系统调用/中断返回时检查并递送信号（check_signals）
//! - 执行默认信号动作（Terminate / Ignore / Core / Stop / Continue）
//! - 用户态信号处理函数的调用和 sigreturn 处理

use core::{future::poll_fn, task::Poll};

use axerrno::{AxError, AxResult};
use axhal::uspace::UserContext;
use axtask::{TaskInner, current, future::block_on};
use starry_process::Pid;
use starry_signal::{SignalInfo, SignalOSAction, SignalSet, Signo};

use super::{AsThread, ProcessData, Thread, do_exit, get_process_data, get_process_group, get_task};

pub fn check_signals(
    thr: &Thread,
    uctx: &mut UserContext,
    restore_blocked: Option<SignalSet>,
) -> bool {
    let Some((sig, os_action)) = thr.signal.check_signals(uctx, restore_blocked) else {
        return false;
    };

    let signo = sig.signo();
    match os_action {
        SignalOSAction::Terminate => {
            do_exit(signo as i32, true);
        }
        SignalOSAction::CoreDump => {
            // TODO: implement core dump
            do_exit(128 + signo as i32, true);
        }
        SignalOSAction::Stop => {
            // TODO: implement job-control stop (SIGSTOP/SIGTSTP/SIGTTIN/SIGTTOU)
        }
        SignalOSAction::Continue => {
            // TODO: implement continue
        }
        SignalOSAction::Handler => {
            // do nothing
        }
    }
    true
}

pub fn block_next_signal() {
    current().as_thread().block_next_signal_check();
}

pub fn with_blocked_signals<R>(
    blocked: Option<SignalSet>,
    f: impl FnOnce() -> AxResult<R>,
) -> AxResult<R> {
    let curr = current();
    let sig = &curr.as_thread().signal;

    let old_blocked = blocked.map(|set| sig.set_blocked(set));
    let result = f();
    if let Some(old) = old_blocked {
        sig.set_blocked(old);
    }
    result
}

fn wake_matching_signal_waiter(proc_data: &ProcessData, signo: Signo) -> bool {
    for tid in proc_data.proc.threads() {
        let Ok(task) = get_task(tid) else {
            continue;
        };
        let Some(thread) = task.try_as_thread() else {
            continue;
        };
        if thread.waiting_for_signal(signo) {
            task.interrupt();
            return true;
        }
    }
    false
}

pub(super) fn send_signal_thread_inner(task: &TaskInner, thr: &Thread, sig: SignalInfo) {
    let signo = sig.signo();
    if thr.signal.process().signal_ignored(signo) {
        return;
    }

    let wake_sigwait = thr.waiting_for_signal(signo);
    if thr.signal.send_signal(sig) || wake_sigwait {
        task.interrupt();
    }
}

fn notify_parent_child_status_change(pid: Pid) {
    let Ok(proc_data) = get_process_data(pid) else {
        return;
    };
    let Some(parent) = proc_data.proc.parent() else {
        return;
    };

    let _ = send_signal_to_process(parent.pid(), Some(SignalInfo::new_kernel(Signo::SIGCHLD)));
    if let Ok(parent_data) = get_process_data(parent.pid()) {
        parent_data.child_exit_event.wake();
    }
}

fn wait_current_ptrace_stop(signo: Signo) {
    let curr = current();
    let thr = curr.as_thread();
    let proc_data = &thr.proc_data;

    proc_data.set_ptrace_stop_signal(signo);
    notify_parent_child_status_change(proc_data.proc.pid());

    block_on(poll_fn(|cx| {
        proc_data.ptrace_stop_event.register(cx.waker());

        if thr.pending_exit() || proc_data.ptrace_stop_signal().is_none() {
            return Poll::Ready(());
        }
        if thr.signal.pending().has(Signo::SIGKILL) || proc_data.proc.is_group_exited() {
            proc_data.clear_ptrace_stop_signal();
            return Poll::Ready(());
        }

        let _ = curr.poll_interrupt(cx);
        if thr.signal.pending().has(Signo::SIGKILL) || proc_data.proc.is_group_exited() {
            proc_data.clear_ptrace_stop_signal();
            Poll::Ready(())
        } else {
            Poll::Pending
        }
    }));
}

/// Sends a signal to a thread.
pub fn send_signal_to_thread(tgid: Option<Pid>, tid: Pid, sig: Option<SignalInfo>) -> AxResult<()> {
    let task = get_task(tid)?;
    let thread = task.try_as_thread().ok_or(AxError::OperationNotPermitted)?;
    if tgid.is_some_and(|tgid| thread.proc_data.proc.pid() != tgid) {
        return Err(AxError::NoSuchProcess);
    }

    if let Some(sig) = sig {
        info!("Send signal {:?} to thread {}", sig.signo(), tid);
        send_signal_thread_inner(&task, thread, sig);
    }

    Ok(())
}

/// Sends a signal to a process.
pub fn send_signal_to_process(pid: Pid, sig: Option<SignalInfo>) -> AxResult<()> {
    let proc_data = get_process_data(pid)?;

    if let Some(sig) = sig {
        let signo = sig.signo();
        info!("Send signal {signo:?} to process {pid}");
        if signo == Signo::SIGKILL {
            proc_data.clear_ptrace_stop_signal();
            for tid in proc_data.proc.threads() {
                let _ = send_signal_to_thread(None, tid, Some(sig.clone()));
            }
            return Ok(());
        }
        let current_is_target = current()
            .try_as_thread()
            .is_some_and(|thr| thr.proc_data.proc.pid() == pid);
        if current_is_target && proc_data.is_ptrace_traceme() {
            wait_current_ptrace_stop(signo);
            return Ok(());
        }
        if let Some(tid) = proc_data.signal.send_signal(sig)
            && let Ok(task) = get_task(tid)
        {
            task.interrupt();
        } else if !proc_data.signal.signal_ignored(signo) {
            wake_matching_signal_waiter(&proc_data, signo);
        }
    }

    Ok(())
}

/// Sends a signal to a process group.
pub fn send_signal_to_process_group(pgid: Pid, sig: Option<SignalInfo>) -> AxResult<()> {
    let pg = get_process_group(pgid)?;

    if let Some(sig) = sig {
        info!("Send signal {:?} to process group {}", sig.signo(), pgid);
        for proc in pg.processes() {
            send_signal_to_process(proc.pid(), Some(sig.clone()))?;
        }
    }

    Ok(())
}

/// Sends a fatal signal to the current process.
pub fn raise_signal_fatal(sig: SignalInfo) -> AxResult<()> {
    let curr = current();
    let proc_data = &curr.as_thread().proc_data;

    let signo = sig.signo();
    info!("Send fatal signal {signo:?} to the current process");
    if let Some(tid) = proc_data.signal.send_signal(sig)
        && let Ok(task) = get_task(tid)
    {
        task.interrupt();
    } else {
        // No task wants to handle the signal, abort the task
        do_exit(signo as i32, true);
    }

    Ok(())
}

