/// Creates a new empty user address space.
pub fn new_user_aspace_empty() -> AxResult<AddrSpace> {
    AddrSpace::new_empty(VirtAddr::from_usize(USER_SPACE_BASE), USER_SPACE_SIZE)
}

/// If the target architecture requires it, the kernel portion of the address
/// space will be copied to the user address space.
pub fn copy_from_kernel(_aspace: &mut AddrSpace) -> AxResult {
    #[cfg(not(any(target_arch = "aarch64", target_arch = "loongarch64")))]
    {
        // ARMv8 (aarch64) and LoongArch64 use separate page tables for user space
        // (aarch64: TTBR0_EL1, LoongArch64: PGDL), so there is no need to copy the
        // kernel portion to the user page table.
        let kspace = axmm::kernel_aspace().lock();
        crate::mm::aspace::with_page_table_cursor(_aspace.page_table_mut(), |cursor| {
            cursor.copy_from(kspace.page_table(), kspace.base(), kspace.size());
        });
    }
    Ok(())
}

/// Signal trampoline address range recorded so MAP_FIXED cannot overwrite it.
static TRAMPOLINE_ADDR: core::sync::atomic::AtomicUsize = core::sync::atomic::AtomicUsize::new(0);

/// Returns `true` if the given address range overlaps the signal trampoline page.
pub fn overlaps_trampoline(start: usize, size: usize) -> bool {
    let tramp = TRAMPOLINE_ADDR.load(core::sync::atomic::Ordering::Relaxed);
    tramp != 0 && (start..start + size).contains(&tramp)
}

/// Map the signal trampoline to the user address space.
pub fn map_trampoline(aspace: &mut AddrSpace) -> AxResult {
    let tramp_addr = crate::config::SIGNAL_TRAMPOLINE;
    TRAMPOLINE_ADDR.store(tramp_addr, core::sync::atomic::Ordering::Relaxed);
    let signal_trampoline_paddr =
        virt_to_phys(starry_signal::arch::signal_trampoline_address().into());
    aspace.map_linear(
        tramp_addr.into(),
        signal_trampoline_paddr,
        PAGE_SIZE_4K,
        MappingFlags::READ | MappingFlags::EXECUTE | MappingFlags::USER,
    )?;
    Ok(())
}

fn mapping_flags(flags: xmas_elf::program::Flags) -> MappingFlags {
    let mut mapping_flags = MappingFlags::USER;
    if flags.is_read() {
        mapping_flags |= MappingFlags::READ;
    }
    if flags.is_write() {
        mapping_flags |= MappingFlags::WRITE;
    }
    if flags.is_execute() {
        mapping_flags |= MappingFlags::EXECUTE;
    }
    mapping_flags
}

fn resolve_interpreter_path(path: &str) -> String {
