    let fallbacks: &[&str] = match path {
        "/lib/ld-linux-riscv64-lp64d.so.1"
        | "/lib64/ld-linux-riscv64-lp64d.so.1"
        | "/lib/ld-linux-riscv64-lp64.so.1" => &[
            "/glibc/lib/ld-linux-riscv64-lp64d.so.1",
            "/glibc/lib/ld-linux-riscv64-lp64.so.1",
        ],
        "/lib/ld-musl-riscv64.so.1" | "/lib/ld-musl-riscv64-sf.so.1" => &[
            "/musl/lib/libc.so",
            "/lib/ld-musl-riscv64.so.1",
            "/lib/ld-musl-riscv64-sf.so.1",
        ],
        "/lib/ld-linux-aarch64.so.1" => &["/glibc/lib/ld-linux-aarch64.so.1"],
        "/lib64/ld-linux-loongarch-lp64d.so.1" | "/lib/ld-linux-loongarch-lp64d.so.1" => &[
            "/glibc/lib/ld-linux-loongarch-lp64d.so.1",
            "/lib/ld-linux-loongarch-lp64d.so.1",
            "/lib64/ld-linux-loongarch-lp64d.so.1",
        ],
        "/lib/ld-musl-loongarch-lp64d.so.1"
        | "/lib64/ld-musl-loongarch-lp64d.so.1"
        | "/lib/ld-musl-loongarch64.so.1" => &[
            "/musl/lib/libc.so",
            "/lib/ld-musl-loongarch64.so.1",
            "/lib/ld-musl-loongarch-lp64d.so.1",
            "/lib64/ld-musl-loongarch-lp64d.so.1",
        ],
        _ => &[],
    };

    fallbacks
        .iter()
        .find(|path| resolve_cached_path(path).is_ok())
        .map_or_else(|| path.to_owned(), |path| (*path).to_owned())
}

fn resolve_cached_path(path: &str) -> AxResult<Location> {
    if path.starts_with('/') {
        if let Some(loc) = cached_absolute_location(path) {
            return Ok(loc);
        }
        let loc = FS_CONTEXT.lock().resolve(path)?;
        cache_absolute_location(path.to_owned(), loc.clone());
        Ok(loc)
    } else {
        FS_CONTEXT.lock().resolve(path).map_err(Into::into)
    }
}

/// Map the elf file to the user address space.
///
/// # Arguments
/// - `uspace`: The address space of the user app.
/// - `elf`: The elf file.
///
/// # Returns
/// - The entry point of the user app.
fn map_elf<'a>(
    uspace: &mut AddrSpace,
    base: usize,
    entry: &'a ElfCacheEntry,
) -> AxResult<ELFParser<'a>> {
    let elf_parser = ELFParser::new(entry.borrow_elf(), base).map_err(|_| AxError::InvalidData)?;
    let cache = entry.borrow_cache();

    for ph in elf_parser
        .headers()
        .ph
        .iter()
        .filter(|ph| ph.get_type() == Ok(xmas_elf::program::Type::Load))
    {
        let vaddr = ph.virtual_addr as usize + elf_parser.base();
        debug!(
            "Mapping ELF segment: [{:#x?}, {:#x?}) flags: {}",
            vaddr,
            vaddr + ph.mem_size as usize,
            ph.flags
        );
        let seg_pad = vaddr.align_offset_4k();
        assert_eq!(seg_pad, ph.offset as usize % PAGE_SIZE_4K);

        let mem_size = ph.mem_size as usize;
        let raw_size = mem_size
            .checked_add(seg_pad)
            .and_then(|v| v.checked_add(PAGE_SIZE_4K - 1))
            .ok_or(AxError::InvalidData)?;
        let seg_align_size = raw_size & !(PAGE_SIZE_4K - 1);
        let seg_start = VirtAddr::from_usize(vaddr);

        // Note that `offset` might not be aligned to 4K here, and it's
        // backend's responsibility to properly handle it.
        let backend = Backend::new_cow(
            seg_start,
            PageSize::Size4K,
            FileBackend::Cached(cache.clone()),
            ph.offset,
            Some(ph.offset + ph.file_size),
        );
        uspace.map(
            seg_start.align_down_4k(),
            seg_align_size,
            mapping_flags(ph.flags),
            false,
            backend,
        )?;

        if ph.flags.is_execute() {
            #[cfg(any(target_arch = "riscv32", target_arch = "riscv64"))]
            unsafe {
                core::arch::asm!("fence.i");
            }
        }
    }

    Ok(elf_parser)
}

fn map_elf_error(err: &'static str) -> AxError {
    debug!("Failed to parse ELF file: {err}");
    AxError::InvalidExecutable
}

