//! execve 系统调用实现。
//!
//! execve 将当前进程替换为新程序。这是 Linux 中唯一"创建新进程但不返回"的
//! 系统调用——成功时调用者的地址空间被完全替换，失败时返回错误码。
//!
//! # 执行流程
//!
//! 1. 解析可执行文件路径（通过 VFS 查找）
//! 2. 读取 ELF 头，验证格式和架构兼容性
//! 3. 释放当前地址空间（除了必需的页表结构）
//! 4. 创建新的地址空间，加载 ELF 段（代码、数据、BSS）
//! 5. 设置新栈（包含 argv、envp、auxv）
//! 6. 设置用户上下文入口点并跳转

use alloc::{
    string::{String, ToString},
    sync::Arc,
    vec::Vec,
};
use core::{ffi::c_char, mem::MaybeUninit, slice};

use axerrno::{AxError, AxResult};
use axfs::FS_CONTEXT;
use axhal::uspace::UserContext;
use axtask::current;
use starry_vm::vm_read_slice;

use crate::{
    config::USER_HEAP_BASE,
    file::{FD_TABLE, close_file_descriptor},
    mm::{load_user_app, vm_load_string},
    task::AsThread,
};

const MAX_EXEC_PTRS_BYTES: usize = 131072;

fn load_exec_strings(ptr: *const *const c_char) -> AxResult<Vec<String>> {
    if ptr.is_null() {
        return Ok(Vec::new());
    }

    let max_ptrs = MAX_EXEC_PTRS_BYTES / size_of::<*const c_char>();
    let mut strings = Vec::new();
    for i in 0..max_ptrs {
        let mut slot = MaybeUninit::<*const c_char>::uninit();
        // SAFETY: `i` is bounded by `max_ptrs`, and `vm_read_slice` validates
        // that the resulting pointer addresses readable user memory.
        vm_read_slice(unsafe { ptr.add(i) }, slice::from_mut(&mut slot))?;
        // SAFETY: raw pointers are plain values; the pointed-to string is
        // validated by `vm_load_string` below.
        let string_ptr = unsafe { slot.assume_init() };
        if string_ptr.is_null() {
            return Ok(strings);
        }
        strings.push(vm_load_string(string_ptr)?);
    }

    Err(AxError::ArgumentListTooLong)
}

pub fn sys_execve(
    uctx: &mut UserContext,
    path: *const c_char,
    argv: *const *const c_char,
    envp: *const *const c_char,
) -> AxResult<isize> {
    let path = vm_load_string(path)?;

    let mut args = load_exec_strings(argv)?;
    if args.is_empty() {
        // Linux permits NULL or empty argv, but our loader expects argv[0].
        args.push(path.clone());
    }

    let envs = load_exec_strings(envp)?;

    debug!("sys_execve <= path: {path:?}, args: {args:?}, envs: {envs:?}");

    let curr = current();
    let proc_data = &curr.as_thread().proc_data;

    if proc_data.proc.threads().len() > 1 {
        // TODO: handle multi-thread case
        error!("sys_execve: multi-thread not supported");
        return Err(AxError::WouldBlock);
    }

    let (entry_point, user_stack_base, new_page_table_root) = {
        let mut aspace = proc_data.aspace.lock();
        let (entry_point, user_stack_base) =
            load_user_app(&mut aspace, Some(path.as_str()), &args, &envs)?;
        (entry_point, user_stack_base, aspace.page_table_root())
    };

    curr.set_page_table_root(new_page_table_root);
    unsafe {
        axhal::asm::write_user_page_table(new_page_table_root);
    }
    axhal::asm::flush_tlb(None);

    let loc = FS_CONTEXT.lock().resolve(&path)?;
    curr.set_name(loc.name());

    *proc_data.exe_path.write() = loc.absolute_path()?.to_string();
    *proc_data.cmdline.write() = Arc::new(args);

    proc_data.set_heap_top(USER_HEAP_BASE);
    curr.as_thread().complete_vfork();

    *proc_data.signal.actions.lock() = Default::default();

    // Clear thread pointers that referenced the pre-exec image.
    curr.as_thread().set_clear_child_tid(0);
    curr.as_thread().set_robust_list_head(0);

    // Close CLOEXEC file descriptors
    let mut fd_table = FD_TABLE.write();
    if fd_table.has_cloexec() {
        let cloexec_fds = fd_table
            .ids()
            .filter(|it| fd_table.get(*it).unwrap().cloexec)
            .collect::<Vec<_>>();
        for fd in cloexec_fds {
            if let Some(descriptor) = fd_table.remove(fd) {
                close_file_descriptor(descriptor);
            }
        }
    }
    drop(fd_table);

    uctx.set_ip(entry_point.as_usize());
    uctx.set_sp(user_stack_base.as_usize());
    Ok(0)
}

