struct Random {
    rng: Mutex<SmallRng>,
}

impl Random {
    pub fn new() -> Self {
        // Use wall clock nanos as entropy source — not cryptographically
        // secure but avoids deterministic output across boots.
        let t = axhal::time::wall_time_nanos();
        let t_bytes = t.to_ne_bytes();
        let mut seed = [0u8; 32];
        seed[..8].copy_from_slice(&t_bytes);
        seed[8..16].copy_from_slice(&t_bytes);
        seed[16..24].copy_from_slice(&t_bytes);
        seed[24..32].copy_from_slice(&t_bytes);
        Self {
            rng: Mutex::new(SmallRng::from_seed(seed)),
        }
    }
}

impl DeviceOps for Random {
    fn read_at(&self, buf: &mut [u8], _offset: u64) -> VfsResult<usize> {
        self.rng.lock().fill_bytes(buf);
