/// Wait queue used by futex.
#[derive(Default)]
pub struct WaitQueue {
    queue: SpinNoIrq<VecDeque<Waiter>>,
}

struct Waiter {
    id: usize,
    task: WeakAxTaskRef,
    waker: Waker,
    bitset: u32,
}

static NEXT_WAITER_ID: AtomicUsize = AtomicUsize::new(1);

fn waiter_is_alive(waiter: &Waiter) -> bool {
    match waiter.task.upgrade() {
        Some(t) => t.state() != TaskState::Exited,
        None => false,
    }
}

impl WaitQueue {
    /// Creates a new `WaitQueue`.
    pub fn new() -> Self {
        Self::default()
    }

    /// Waits if the given condition is met.
    ///
    /// Returns `false` if the condition is not met and no actual waiting
    /// occurs.
    pub fn wait_if(
        &self,
        bitset: u32,
        deadline: Option<TimeValue>,
        mut condition: impl FnMut() -> bool,
    ) -> AxResult<bool> {
        let waiter_id = NEXT_WAITER_ID.fetch_add(1, Ordering::Relaxed);
        let mut registered = false;
        let res = block_on(interruptible(future::timeout_at(
            deadline,
            poll_fn(|cx| {
                if !registered {
                    if !condition() {
                        Poll::Ready(Ok(false))
                    } else {
                        {
                            let mut queue = self.queue.lock();
                            queue.push_back(Waiter {
                                id: waiter_id,
                                task: Arc::downgrade(&*current()),
                                waker: cx.waker().clone(),
                                bitset,
                            });
                        }
                        registered = true;

                        // Recheck after enqueueing. If the futex value changed
                        // between the first check and queue insertion, remove
                        // the waiter and return without sleeping. The user-memory
                        // read must stay outside the SpinNoIrq queue lock.
                        if condition() {
                            Poll::Pending
                        } else {
                            self.remove_waiter(waiter_id);
                            Poll::Ready(Ok(false))
                        }
                    }
                } else {
                    let mut queue = self.queue.lock();
                    if let Some(waiter) = queue.iter_mut().find(|waiter| waiter.id == waiter_id) {
                        waiter.waker = cx.waker().clone();
                        Poll::Pending
                    } else {
                        Poll::Ready(Ok(true))
                    }
                }
            }),
        )));
        self.remove_waiter(waiter_id);
        res??
    }

    /// Wakes up at most `count` tasks whose bitset intersects with the given
    /// bitmask.
    pub fn wake(&self, count: usize, mask: u32) -> usize {
        let mut wakers = Vec::new();
        self.queue.lock().retain(|waiter| {
            if !waiter_is_alive(waiter) {
                return false;
            }
            if wakers.len() >= count || (waiter.bitset & mask) == 0 {
                true
            } else {
                wakers.push(waiter.waker.clone());
                false
            }
        });
        let woke = wakers.len();
        for waker in wakers {
            waker.wake();
        }
        woke
    }

    /// Checks if the wait queue is empty.
    pub fn is_empty(&self) -> bool {
        self.queue.lock().is_empty()
    }

    /// Requeue at most `count` tasks to the target wait queue.
    pub fn requeue(&self, count: usize, target: &WaitQueue) -> usize {
        let mut tasks = Vec::new();
        let mut requeued = 0;
        {
            let mut wq = self.queue.lock();
            let mut keep = VecDeque::new();
            while let Some(waiter) = wq.pop_front() {
                if !waiter_is_alive(&waiter) {
                    continue;
                }
                if requeued < count {
                    tasks.push(waiter);
                    requeued += 1;
                } else {
                    keep.push_back(waiter);
                }
            }
            wq.extend(keep);
        }
        if !tasks.is_empty() {
            let mut wq = target.queue.lock();
            wq.extend(tasks);
        }
        requeued
    }

    fn remove_waiter(&self, id: usize) {
        self.queue.lock().retain(|waiter| waiter.id != id);
    }
}

/// A key that uniquely identifies a futex in the system.
pub enum FutexKey {
    /// A futex that is private to the current process.
    Private {
        /// The memory address of the futex.
        address: usize,
    },

    /// A futex in a shared memory region.
    Shared {
        /// The offset of the futex within the shared memory region.
        offset: usize,
        /// The shared memory region.
        region: Result<Weak<SharedPages>, Weak<()>>,
    },
}

impl FutexKey {
    /// Creates a new `FutexKey`.
    pub fn new(aspace: &AddrSpace, address: usize) -> Self {
        if let Some(area) = aspace.find_area(VirtAddr::from_usize(address)) {
            match area.backend() {
                Backend::Shared(backend) => {
                    return Self::Shared {
                        offset: address - area.start().as_usize(),
                        region: Ok(Arc::downgrade(backend.pages())),
                    };
                }
                Backend::File(file) => {
                    return Self::Shared {
                        offset: address - area.start().as_usize(),
                        region: Err(file.futex_handle()),
                    };
                }
                _ => {}
            }
        }
        Self::Private { address }
    }

    /// Shortcut to create a `FutexKey` for the current task's address space.
    pub fn new_current(address: usize) -> Self {
        Self::new(&current().as_thread().proc_data.aspace.lock(), address)
    }

    fn as_usize(&self) -> usize {
        match self {
            FutexKey::Private { address } => *address,
            FutexKey::Shared { offset, .. } => *offset,
        }
    }
}

