//! futex 系统调用实现。
//!
//! futex（Fast Userspace muTEX）是 Linux 中实现用户态锁的基础原语。
//! pthread_mutex、semaphore、barrier 等最终都通过 futex 实现。
//!
//! # 主要操作
//!
//! - FUTEX_WAIT: 在共享内存地址上等待（原子检查值 → 睡眠）
//! - FUTEX_WAKE: 唤醒等待在共享内存地址上的线程
//! - FUTEX_REQUEUE: 将等待者从 uaddr 迁移到 uaddr2
//! - FUTEX_WAIT_BITSET / FUTEX_WAKE_BITSET: 带位掩码的等待/唤醒
//!
//! # robust_list
//!
//! 支持 get_robust_list / set_robust_list，用于线程异常终止时
//! 内核自动释放其持有的 futex（通过 robust mutex 机制）。

use core::sync::atomic::Ordering;

use axerrno::{AxError, AxResult, LinuxError};
use axhal::time::{TimeValue, monotonic_time, wall_time};
use axtask::current;
use linux_raw_sys::general::{
    FUTEX_CLOCK_REALTIME, FUTEX_CMD_MASK, FUTEX_CMP_REQUEUE, FUTEX_REQUEUE, FUTEX_WAIT,
    FUTEX_WAIT_BITSET, FUTEX_WAKE, FUTEX_WAKE_BITSET, robust_list_head, timespec,
};
use starry_vm::{VmMutPtr, VmPtr};

use crate::{
    task::{AsThread, FutexKey, futex_table_for, get_task},
    time::TimeValueLike,
};

fn assert_unsigned(value: u32) -> AxResult<u32> {
    if (value as i32) < 0 {
        Err(AxError::InvalidInput)
    } else {
        Ok(value)
    }
}

fn futex_relative_deadline(timeout: Option<TimeValue>) -> Option<TimeValue> {
    timeout.and_then(|duration| wall_time().checked_add(duration))
}

fn futex_absolute_deadline(deadline: TimeValue, realtime: bool) -> TimeValue {
    let now = if realtime {
        wall_time()
    } else {
        monotonic_time()
    };
    let remaining = deadline.checked_sub(now).unwrap_or_default();
    wall_time() + remaining
}

fn futex_value_matches(uaddr: *const u32, value: u32) -> bool {
    // Pre-read the futex word outside any lock. The caller rechecks this under
    // the queue lock, so a transient mismatch is harmless — the wait loop will
    // retry. This avoids touching user memory inside a SpinNoIrq critical section.
    let Ok(current) = uaddr.vm_read() else {
        return false;
    };
    current == value
}

pub fn sys_futex(
    uaddr: *const u32,
    futex_op: u32,
    value: u32,
    timeout: *const timespec,
    uaddr2: *mut u32,
    value3: u32,
) -> AxResult<isize> {
    debug!(
        "sys_futex <= uaddr: {uaddr:?}, futex_op: {futex_op}, value: {value}, uaddr2: {uaddr2:?}, \
         value3: {value3}",
    );

    let key = FutexKey::new_current(uaddr.addr());

    let futex_table = futex_table_for(&key);

    let command = futex_op & (FUTEX_CMD_MASK as u32);
    let realtime = (futex_op & FUTEX_CLOCK_REALTIME) != 0;
    match command {
        FUTEX_WAIT | FUTEX_WAIT_BITSET => {
            // Fast path
            if uaddr.vm_read()? != value {
                return Err(AxError::WouldBlock);
            }

            let timeout = if let Some(ts) = timeout.nullable() {
                // FIXME: AnyBitPattern
                let ts = unsafe { ts.vm_read_uninit()?.assume_init() }.try_into_time_value()?;
                Some(ts)
            } else {
                None
            };
            let deadline = match (command, timeout) {
                (FUTEX_WAIT, timeout) => futex_relative_deadline(timeout),
                (FUTEX_WAIT_BITSET, Some(deadline)) => {
                    Some(futex_absolute_deadline(deadline, realtime))
                }
                (FUTEX_WAIT_BITSET, None) => None,
                _ => unreachable!(),
            };

            let futex = futex_table.get_or_insert(&key);

            let bitset = if command == FUTEX_WAIT_BITSET {
                value3
            } else {
                u32::MAX
            };

            if !futex
                .wq
                .wait_if(bitset, deadline, || futex_value_matches(uaddr, value))?
            {
                return Err(AxError::WouldBlock);
            }

            if futex.owner_dead.swap(false, Ordering::SeqCst) {
                Err(AxError::from(LinuxError::EOWNERDEAD))
            } else {
                Ok(0)
            }
        }
        FUTEX_WAKE | FUTEX_WAKE_BITSET => {
            let futex = futex_table.get(&key);
            let mut count = 0;
            if let Some(futex) = futex {
                let bitset = if command == FUTEX_WAKE_BITSET {
                    value3
                } else {
                    u32::MAX
                };
                count = futex.wq.wake(value as _, bitset);
            }
            if count > 0 {
                axtask::yield_now();
            }
            Ok(count as _)
        }
        FUTEX_REQUEUE | FUTEX_CMP_REQUEUE => {
            assert_unsigned(value)?;
            if command == FUTEX_CMP_REQUEUE && uaddr.vm_read()? != value3 {
                return Err(AxError::WouldBlock);
            }
            let value2 = assert_unsigned(timeout.addr() as u32)?;

            let futex = futex_table.get(&key);
            let key2 = FutexKey::new_current(uaddr2.addr());
            let table2 = futex_table_for(&key2);
            let futex2 = table2.get_or_insert(&key2);

            let mut count = 0;
            if let Some(futex) = futex {
                count = futex.wq.wake(value as _, u32::MAX);
                if count == value as usize {
                    count += futex.wq.requeue(value2 as _, &futex2.wq) as usize;
                }
            }
            Ok(count as _)
        }
        _ => Err(AxError::Unsupported),
    }
}

pub fn sys_get_robust_list(
    tid: u32,
    head: *mut *const robust_list_head,
    size: *mut usize,
) -> AxResult<isize> {
    let task = get_task(tid)?;
    head.vm_write(task.as_thread().robust_list_head() as _)?;
    size.vm_write(size_of::<robust_list_head>())?;

    Ok(0)
}

pub fn sys_set_robust_list(head: *const robust_list_head, size: usize) -> AxResult<isize> {
    if size != size_of::<robust_list_head>() {
        return Err(AxError::InvalidInput);
    }
    current().as_thread().set_robust_list_head(head.addr());

    Ok(0)
}

