const RING_BUFFER_INIT_SIZE: usize = 256 * 1024;
const PIPE_INTERACTIVE_YIELD_LIMIT: usize = 64;

unsafe fn slice_assume_init_mut<T>(slice: &mut [MaybeUninit<T>]) -> &mut [T] {
    unsafe { &mut *(slice as *mut [MaybeUninit<T>] as *mut [T]) }
}

struct Shared {
    buffer: SpinNoIrq<HeapRb<u8>>,
    readers: AtomicUsize,
    writers: AtomicUsize,
    poll_rx: PollSet,
    poll_tx: PollSet,
    poll_close: PollSet,
}

pub struct Pipe {
    read_side: bool,
    shared: Arc<Shared>,
    non_blocking: AtomicBool,
}
impl Drop for Pipe {
    fn drop(&mut self) {
        if self.read_side {
            self.shared.readers.fetch_sub(1, Ordering::AcqRel);
        } else {
            self.shared.writers.fetch_sub(1, Ordering::AcqRel);
        }
        self.shared.poll_rx.wake();
        self.shared.poll_tx.wake();
        self.shared.poll_close.wake();
    }
}

impl Pipe {
    pub fn new() -> (Pipe, Pipe) {
        let shared = Arc::new(Shared {
            buffer: SpinNoIrq::new(HeapRb::new(RING_BUFFER_INIT_SIZE)),
            readers: AtomicUsize::new(1),
            writers: AtomicUsize::new(1),
            poll_rx: PollSet::new(),
            poll_tx: PollSet::new(),
            poll_close: PollSet::new(),
        });
        let read_end = Pipe {
            read_side: true,
            shared: shared.clone(),
            non_blocking: AtomicBool::new(false),
        };
        let write_end = Pipe {
            read_side: false,
            shared,
            non_blocking: AtomicBool::new(false),
        };
        (read_end, write_end)
    }

    pub const fn is_read(&self) -> bool {
        self.read_side
    }

    pub const fn is_write(&self) -> bool {
        !self.read_side
    }

    pub fn closed(&self) -> bool {
        if self.read_side {
            self.shared.writers.load(Ordering::Acquire) == 0
        } else {
            self.shared.readers.load(Ordering::Acquire) == 0
        }
    }

    pub fn capacity(&self) -> usize {
        self.shared.buffer.lock().capacity().get()
    }

    pub fn resize(&self, new_size: usize) -> AxResult<()> {
        let new_size = new_size.div_ceil(PAGE_SIZE_4K).max(1) * PAGE_SIZE_4K;

        let mut buffer = self.shared.buffer.lock();
        if new_size == buffer.capacity().get() {
            return Ok(());
        }
        if new_size < buffer.occupied_len() {
            return Err(AxError::ResourceBusy);
        }
        let old_buffer = mem::replace(&mut *buffer, HeapRb::new(new_size));
        let (left, right) = old_buffer.as_slices();
        buffer.push_slice(left);
        buffer.push_slice(right);
        Ok(())
    }

    fn try_read_once(&self, dst: &mut IoDst) -> AxResult<usize> {
        let read = {
            let cons = self.shared.buffer.lock();
            let was_full = cons.vacant_len() == 0;
            let (left, right) = cons.as_slices();
            let mut count = dst.write(left)?;
            if count >= left.len() {
                count += dst.write(right)?;
            }
            unsafe { cons.advance_read_index(count) };
            (count, was_full)
        };
        if read.0 > 0 {
            if read.1 {
                let woke = self.shared.poll_tx.wake();
                if woke > 0 && read.0 <= PIPE_INTERACTIVE_YIELD_LIMIT && !self.nonblocking() {
                    yield_now();
                }
            }
            Ok(read.0)
        } else if self.closed() {
            Ok(0)
        } else {
            Err(AxError::WouldBlock)
        }
    }

    fn try_write_once(
        &self,
        src: &mut IoSrc,
        total_written: &mut usize,
        size: usize,
    ) -> AxResult<usize> {
        if self.closed() {
            raise_pipe();
            return Err(AxError::BrokenPipe);
        }

        let written = {
            let mut prod = self.shared.buffer.lock();
            let was_empty = prod.occupied_len() == 0;
            let (left, right) = prod.vacant_slices_mut();
            let mut count = src.read(unsafe { slice_assume_init_mut(left) })?;
            if count >= left.len() {
                count += src.read(unsafe { slice_assume_init_mut(right) })?;
            }
            unsafe { prod.advance_write_index(count) };
            (count, was_empty)
        };
        if written.0 > 0 {
            if written.1 {
                let woke = self.shared.poll_rx.wake();
                // Small blocking pipe writes are usually handoff-style traffic
                // (shell/control pipes, process rings). Yield even when the
                // reader has not registered a waker yet so the peer can consume
                // the byte before it falls into the blocking slow path.
                if (woke > 0 || self.shared.readers.load(Ordering::Acquire) > 0)
                    && written.0 <= PIPE_INTERACTIVE_YIELD_LIMIT
                    && !self.nonblocking()
                {
                    yield_now();
                }
            }
            *total_written += written.0;
            if *total_written == size || self.nonblocking() {
                return Ok(*total_written);
            }
        }
        Err(AxError::WouldBlock)
    }
}

fn raise_pipe() {
    let curr = current();
