// ---------------------------------------------------------------------------
// POSIX timers (per-process)
// ---------------------------------------------------------------------------

struct PosixTimer {
    clock_id: u32,
    signo: u32,
    interval_ns: u64,
    deadline: Mutex<Option<Duration>>,
    cancel: Arc<AtomicBool>,
    generation: u64,
}

struct ProcessTimerTable {
    next_id: i32,
    timers: Vec<Option<PosixTimer>>,
}

static POSIX_TIMERS: Mutex<BTreeMap<Pid, ProcessTimerTable>> = Mutex::new(BTreeMap::new());

fn with_timer<R>(
    pid: Pid,
    id: i32,
    f: impl FnOnce(&mut PosixTimer) -> AxResult<R>,
) -> AxResult<R> {
    let mut table = POSIX_TIMERS.lock();
    let tbl = table.get_mut(&pid).ok_or(AxError::InvalidInput)?;
    let slot = tbl
        .timers
        .get_mut(id as usize)
        .and_then(|t| t.as_mut())
        .ok_or(AxError::InvalidInput)?;
    f(slot)
}

fn timespec_to_ns(ts: &timespec) -> AxResult<u64> {
    if ts.tv_sec < 0 || ts.tv_nsec < 0 || ts.tv_nsec > 999_999_999 {
        return Err(AxError::InvalidInput);
    }
    Ok(ts.tv_sec as u64 * 1_000_000_000 + ts.tv_nsec as u64)
}

fn ns_to_timespec(ns: u64) -> timespec {
    timespec {
        tv_sec: (ns / 1_000_000_000) as _,
        tv_nsec: (ns % 1_000_000_000) as _,
    }
}

fn remaining_ns(deadline: &Mutex<Option<Duration>>) -> u64 {
    let guard = deadline.lock();
    match *guard {
        Some(d) => {
            let now = wall_time();
            if d > now {
                (d - now).as_nanos() as u64
            } else {
                0
            }
        }
        None => 0,
    }
}

fn get_clock_now(clock_id: u32) -> Duration {
    match clock_id {
        CLOCK_REALTIME => wall_time(),
        CLOCK_MONOTONIC | CLOCK_BOOTTIME
        | CLOCK_PROCESS_CPUTIME_ID | CLOCK_THREAD_CPUTIME_ID => {
            // For CPU-time clocks we approximate with monotonic time.
            // Full per-process CPU accounting would be needed for accuracy.
            axhal::time::monotonic_time()
        }
        _ => wall_time(),
    }
}

// ---------------------------------------------------------------------------
// timer_create
// ---------------------------------------------------------------------------

pub fn sys_timer_create(
    clock_id: u32,
    sevp: *const sigevent,
    timerid_ptr: *mut i32,
) -> AxResult<isize> {
    match clock_id {
        CLOCK_REALTIME | CLOCK_MONOTONIC | CLOCK_BOOTTIME
        | CLOCK_PROCESS_CPUTIME_ID | CLOCK_THREAD_CPUTIME_ID => {}
        _ => return Err(AxError::InvalidInput),
    }

    // Default: SIGEV_SIGNAL / SIGALRM
    let (signo, notify) = if sevp.is_null() {
        (14u32, 0u32) // SIGALRM, SIGEV_SIGNAL
    } else {
        let sev = unsafe { sevp.vm_read_uninit()?.assume_init() };
        (sev.sigev_signo as u32, sev.sigev_notify as u32)
    };

    match notify {
        0 => {} // SIGEV_SIGNAL
        1 => {} // SIGEV_NONE
        _ => {
            warn!("timer_create: unsupported sigev_notify={notify}");
            return Err(AxError::InvalidInput);
        }
    }

    let pid = current_pid();
    let mut table = POSIX_TIMERS.lock();
    let tbl = table.entry(pid).or_insert_with(|| ProcessTimerTable {
        next_id: 0,
        timers: Vec::new(),
    });

    let id = tbl.next_id;
    tbl.next_id += 1;
    if tbl.timers.len() <= id as usize {
        tbl.timers.resize_with(id as usize + 1, || None);
    }
    tbl.timers[id as usize] = Some(PosixTimer {
        clock_id,
        signo,
        interval_ns: 0,
        deadline: Mutex::new(None),
        cancel: Arc::new(AtomicBool::new(false)),
        generation: 0,
    });

    drop(table);

    debug!("timer_create: clock={clock_id} signo={signo} => id={id}");
    timerid_ptr.vm_write(id)?;
    Ok(0)
}

